183	    pub(crate) fn try_io<R>(
184	        &self,
185	        interest: Interest,
186	        f: impl FnOnce() -> io::Result<R>,
187	    ) -> io::Result<R> {
188	        let ev = self.shared.ready_event(interest);
189	
190	        // Don't attempt the operation if the resource is not ready.
191	        if ev.ready.is_empty() {
192	            return Err(io::ErrorKind::WouldBlock.into());
193	        }
194	
195	        match f() {
196	            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
197	                self.clear_readiness(ev);
198	                Err(io::ErrorKind::WouldBlock.into())
199	            }
200	            res => res,

250	            if let Some(waker) = waiters.writer.take() {
251	                wakers.push(waker);
252	            }
253	        }
254	
255	        'outer: loop {
256	            let mut iter = waiters.list.drain_filter(|w| ready.satisfies(w.interest));
257	
258	            while wakers.can_push() {
259	                match iter.next() {
260	                    Some(waiter) => {
261	                        let waiter = unsafe { &mut *waiter.as_ptr() };
262	
263	                        if let Some(waker) = waiter.waker.take() {
264	                            waiter.is_ready = true;
265	                            wakers.push(waker);
266	                        }
267	                    }
268	                    None => {
269	                        break 'outer;
270	                    }
271	                }
272	            }
273	
274	            drop(waiters);
275	
276	            wakers.wake_all();
277	
278	            // Acquire the lock again.
279	            waiters = self.waiters.lock();
280	        }
281	
282	        // Release the lock before notifying
283	        drop(waiters);
284	
285	        wakers.wake_all();
286	    }
