97	    fn poll_read(
98	        mut self: Pin<&mut Self>,
99	        _cx: &mut Context<'_>,
100	        buf: &mut ReadBuf<'_>,
101	    ) -> Poll<io::Result<()>> {
102	        let amt = std::cmp::min(self.len(), buf.remaining());
103	        let (a, b) = self.split_at(amt);
